const path = require('path');

const PROBLEMS_FILE = path.join(__dirname, '../../data/problems.json');

function loadProblems() {
  const raw = fs.readFileSync(PROBLEMS_FILE, 'utf-8');
  return JSON.parse(raw);
}

/**
 * Get problems list with filtering, paging, and metadata.
 * @param {Object} options
 * @param {string[]} [options.difficulty] - array of difficulty strings to filter by
 * @param {number} [options.limit=50] - max number of results to return
 * @param {boolean} [options.includeComponents=false] - whether to include sorted componentLanguages
 * @returns {Object} result with problems and metadata
 */
function getProblemsList({ difficulty, limit = 50, includeComponents = false } = {}) {
  let problems = loadProblems();

  // Filter by difficulty if provided
  if (Array.isArray(difficulty) && difficulty.length > 0) {
    const difficultySet = new Set(difficulty);
    problems = problems.filter(p => difficultySet.has(p.difficulty));
  }

  // Sort by roundId ascending (deterministic ordering)
  problems.sort((a, b) => {
    if (a.roundId < b.roundId) return -1;
    if (a.roundId > b.roundId) return 1;
    return 0;
  });

  const totalProblems = loadProblems().length;
  const filteredCount = problems.length;

  // Apply limit (max 50)
  const appliedLimit = Math.min(limit, 50);
  problems = problems.slice(0, appliedLimit);

  // If includeComponents, add sorted componentLanguages
  if (includeComponents) {
    problems = problems.map(p => {
      const sortedComponents = Array.isArray(p.componentLanguages) ? [...p.componentLanguages].sort() : [];
      return { ...p, componentLanguages: sortedComponents };
    });
  }

  return {
    problems,
    totalProblems,
    filteredCount,
    appliedLimit,
    difficultyBreakdown: getDifficultyBreakdown(problems)
  };
}

function getDifficultyBreakdown(problems) {
  const breakdown = {};
  for (const p of problems) {
    if (p.difficulty) {
      breakdown[p.difficulty] = (breakdown[p.difficulty] || 0) + 1;
    }
  }
  return breakdown;
}

module.exports = {
  getProblemsList
};
